('spanish:5-2-festivals-and-traditions:mcq:41a5eff9', 'spanish', 'spanish:5-2-festivals-and-traditions', '5.2 Festivals and Traditions', 'mcq', 'mcq', 1, '{"question": "Which word means ‘to push’, as in a crowded festival?", "options": ["empujar", "alcanzar", "esconder", "desaparecer"]}'::jsonb, '{"answer": 0, "explain": "empujar = to push. alcanzar = to reach; esconder = to hide; desaparecer = to disappear."}'::jsonb),
('spanish:5-2-festivals-and-traditions:mcq:f08d5665', 'spanish', 'spanish:5-2-festivals-and-traditions', '5.2 Festivals and Traditions', 'mcq', 'mcq', 1, '{"question": "Complete: ‘Es difícil ___ un buen sitio en la procesión porque hay mucha gente.’ (to reach)", "options": ["alcanzar", "empujar", "esconder", "acordarse"]}'::jsonb, '{"answer": 0, "explain": "alcanzar = to reach/achieve. The others are ‘push’, ‘hide’ and ‘remember’."}'::jsonb),
('spanish:5-2-festivals-and-traditions:mcq:d2404469', 'spanish', 'spanish:5-2-festivals-and-traditions', '5.2 Festivals and Traditions', 'mcq', 'mcq', 1, '{"question": "What does ‘acordarse de’ mean, as in ‘se acuerdan de los que ya no están’?", "options": ["to remember (someone)", "to forget (someone)", "to contribute (something)", "to disappear (suddenly)"]}'::jsonb, '{"answer": 0, "explain": "acordarse de = to remember. It is the opposite of olvidarse de (to forget)."}'::jsonb),
