('spanish:5-2-festivals-and-traditions:tf:431ec471', 'spanish', 'spanish:5-2-festivals-and-traditions', '5.2 Festivals and Traditions', 'tf', 'tf', 1, '{"question": "San Fermín is famous for the running of the bulls in Pamplona."}'::jsonb, '{"answer": true, "explain": "San Fermín (July) in Pamplona is famous for el encierro, the running of the bulls."}'::jsonb),
